const http = require('http');
const crypto = require('crypto');
const { Server } = require('socket.io');

const server = http.createServer();
const io = new Server(server, {
  cors: {
    origin: '*',
    methods: ['GET', 'POST']
  }
});

const sessions = new Map();
const players = new Map();

function generateId(bytes = 16) {
  return crypto.randomBytes(bytes).toString('hex');
}

function sanitizeUsername(username) {
  if (typeof username !== 'string') return null;
  const trimmed = username.trim();
  if (trimmed.length < 3 || trimmed.length > 20) return null;
  if (!/^[a-zA-Z0-9_]+$/.test(trimmed)) return null;
  return trimmed;
}

function sanitizeScore(score) {
  const n = Number(score);
  if (!Number.isFinite(n)) return null;
  if (!Number.isInteger(n)) return null;
  if (n < 0) return null;
  return n;
}

function createSession(username) {
  const sessionId = generateId(24);
  const session = {
    sessionId,
    username,
    createdAt: Date.now(),
    lastSeenAt: Date.now()
  };
  sessions.set(sessionId, session);
  return session;
}

function getPlayerState(username) {
  if (!players.has(username)) {
    players.set(username, {
      username,
      score: 0,
      connected: false,
      socketId: null,
      lastMoveAt: 0
    });
  }
  return players.get(username);
}

function broadcastLeaderboard() {
  const leaderboard = [...players.values()]
    .sort((a, b) => b.score - a.score || a.username.localeCompare(b.username))
    .map((p, index) => ({
      rank: index + 1,
      username: p.username,
      score: p.score,
      connected: p.connected
    }));

  io.emit('leaderboard', leaderboard);
}

io.use((socket, next) => {
  const { sessionId } = socket.handshake.auth || {};
  if (!sessionId || typeof sessionId !== 'string') {
    return next(new Error('Unauthorized'));
  }

  const session = sessions.get(sessionId);
  if (!session) {
    return next(new Error('Invalid session'));
  }

  session.lastSeenAt = Date.now();
  socket.session = session;
  next();
});

io.on('connection', (socket) => {
  const session = socket.session;
  const player = getPlayerState(session.username);

  player.connected = true;
  player.socketId = socket.id;

  socket.emit('authenticated', {
    username: session.username,
    sessionId: session.sessionId
  });

  socket.emit('player_state', {
    username: player.username,
    score: player.score
  });

  broadcastLeaderboard();

  socket.on('move', (data = {}) => {
    const moveType = typeof data.moveType === 'string' ? data.moveType : null;
    if (!moveType) return;

    const now = Date.now();
    if (now - player.lastMoveAt < 50) return;
    player.lastMoveAt = now;

    socket.emit('move_accepted', {
      moveType,
      timestamp: now
    });
  });

  socket.on('score_update', (data = {}) => {
    const incomingUsername = sanitizeUsername(data.username);
    const incomingScore = sanitizeScore(data.score);

    if (!incomingUsername || incomingUsername !== player.username) return;
    if (incomingScore === null) return;

    if (incomingScore >= player.score) {
      player.score = incomingScore;
      io.emit('score_changed', {
        username: player.username,
        score: player.score
      });
      broadcastLeaderboard();
    }
  });

  socket.on('logout', () => {
    socket.disconnect(true);
  });

  socket.on('disconnect', () => {
    player.connected = false;
    player.socketId = null;
    broadcastLeaderboard();
  });
});

io.on('connection_error', () => {});

server.listen(process.env.PORT || 3000);